head.script:
	scwin.rowIndex = -1;

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSZZ1200000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 로그인한 사용자 ID 변수설정
		scwin.usrId = comLib.getUsrId();

		// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
		scwin.setAthrSysDivCd();
	};

	/**
	 * 사용자에게 부여가된 권한의 시스템구분코드만을 조회
	 * @param
	 * @return
	 */
	scwin.setAthrSysDivCd = function () {
		var requestData = {};

		// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd":"SCM_0000"};

		var option = {
			action : "sc/authmng/retrieveAthrSysDivCd.do",
			reqData : requestData,
			resData : dltSysDivCdList,
			success : "scwin.retrieveAthrSysDivCdCallback",
			isShowMeg : false
		};
		ajaxLib.requestAjaxSyncCode($p, option);
	};

	/**
	 * 조회 CallBack 실행
	 * @param <Object> resBody
	 * @return
	 */
	scwin.retrieveAthrSysDivCdCallback = function (resBody, e) {
		if (dltSysDivCdList.getRowCount() == 0) {
			// 시스템관리자만 접근이 가능합니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
			return;
		}

		var sysDivCd = comLib.getSysDivCd();

		dmaInqireParam.set("intnSysDivCd", sysDivCd);
		dmaInqireParam.set("usrId", scwin.usrId);

		dmaSaveScrin.set("intnSysDivCd", sysDivCd);

		// 화면 오픈시 자동조회를 한다.
		comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
		scwin.btnInqire_onclick();
	};

	/**
	 * 조회조건에 맞게 data를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		var requestData = {};
		requestData.dmaInqireParam =dmaInqireParam.getJSON();

		var option = {
			action : "zz/authmng/retrieveScrin.do",
			reqData : requestData,
			resData : dltScrinList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireCallback = function(resBody) {
		if (resBody.message.code == "success"){
			txtCnt.setValue(dltScrinList.getRowCount());
		} else {
			comLib.alert($p, "fail");
		}

		// 화면 오픈과 동시에 메뉴상세항목은 초기화 한다.
		if (scwin.rowIndex == -1) { 
			scwin.btnNew_onclick();
		} else {
			grdScrinList.setFocusedCell(scwin.rowIndex, 0, false);
		}
	};

	/**
	 * 대내화면 등록을 위해 신규버튼 클릭시 dataMap 초기화 한다.
	 * @param
	 * @return
	 */
	scwin.btnNew_onclick = function() {
		// 데이터 맵 초기화
		dmaSaveScrin.reset();
		// PK 수정 불가능 하도록 수정(초기에는 활성화, 값이 있으면 비활성화)
		ibxScrinId.setDisabled(false);
		// 최종수정시간은 메뉴목록에서 선택을 했을 경우만 db 내용을 보여준다.
		tbxLastUpdtDt.setValue("");
		// 시스템 구분 값 설정
		dmaSaveScrin.set("intnSysDivCd", comLib.getSysDivCd());
		// 사용여부는 Defualt로  Y 로 셋팅된다.
		dmaSaveScrin.set("useYn", "Y");
		// 신규 flag 설정
		dmaSaveScrin.set("rowStatus", "C");
		// 그리드 선택 초기화
		scwin.rowIndex = -1;
	};

	/**
	 * 메뉴상세에서 기재한 내용을 수정/저장한다.
	 * @param
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		var valRowStatus = dmaSaveScrin.get("rowStatus");
		var newFlag = false;

		if (utilLib.validateGroup(grpDtl, dmaSaveScrin)) {
			newFlag = true;
		} else {
			newFlag = false;
			return;
		}

		if (newFlag) {
			if (valRowStatus != "D") {
				if (valRowStatus == "C") {
					// 중복체크
					var insert = dmaSaveScrin.getJSON();

					for (var idx = 0; idx < dltScrinList.getRowCount(); idx++) {
						if (insert.scrinId == dltScrinList.getCellData(idx, "scrinId")) {
							// {0}(은/는) 중복될 수 없습니다.
							comLib.alert($p, utilLib.getMessage("SCM.INFO.00068", "화면ID"));
							return;
						}
					}
				}

				// 저장할것인지 confirm
				comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveConfirmCallback");
			} else {
				// 삭제할것인지 confirm
				comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
			}
		}
	};

	/**
	 * 수정/저장 ComfirmCallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		var requestData = {};
		requestData.dmaSaveScrin = dmaSaveScrin.getJSON();

		var option = {
			action : "zz/authmng/saveScrinMng.do",
			reqData : requestData,
			success : "scwin.saveScrinMngCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 수정/저장 CallBack 실행한다. 
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveScrinMngCallback = function(resBody) {
		// comLib.alert($p, resBody.message.code_name);

		var stat = dmaSaveScrin.get("rowStatus");

		if (stat == "D") {
			// 삭제되었습니다.\n프로그램의 소스파일....은 서버에서 삭제하시기 바랍니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00326"));
			scwin.btnNew_onclick();
		} else {
			// 저장되었습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00327"));
		}

		scwin.btnInqire_onclick();
	};

	/**
	 * 작업중이던 내용을 취소한다.
	 * @param
	 * @return
	 */
	scwin.btnCancl_onclick = function() {
		// 작업중이던 dataMap을 초기화한다.
		scwin.btnNew_onclick();
		scwin.btnInqire_onclick();
	};

	/**
	 * 화면목록에서 선택한 화면을 삭제한다.
	 * @param
	 * @return
	 */
	scwin.btnDel_onclick = function() {
		var scrinId = "";
		scrinId = dmaSaveScrin.get("scrinId");

		if (scrinId != null || scrinId != "") {
			dmaSaveScrin.set("rowStatus", "D");
			scwin.selectScrinInfo();
		} else {
			// 삭제하고자 하는 데이터 선택 후 삭제하도록 알림
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
		}
	};

	/**
	 * 화면 삭제전 등록된 정보가 있는지 확인한다.
	 * @param
	 * @return
	 */
	scwin.selectScrinInfo = function() {
		var requestData = {};
		requestData.dmaSaveScrin = dmaSaveScrin.getJSON();

		var option = {
			action : "zz/authmng/selectScrinInfo.do",
			reqData : requestData,
			resData : dltInqireScrinInfoList,
			success : "scwin.searchScrinInfoCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 화면 삭제전 등록된 정보조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.searchScrinInfoCallback = function(resBody) {
		var menuCnt = 0;

		if (resBody.message.code == "success") {
			menuCnt = dltInqireScrinInfoList.getCellData(0, "menuCnt");

			if (menuCnt == 0) {
				scwin.btnSave_onclick();
			} else {
				// 사용중인 데이터는 삭제 못하도록 메세지 알림
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00246", dltInqireScrinInfoList.getCellData(0, "scrinNm")));
			}
		}
	};

	/**
	 * 조회된 메뉴목록을 엑셀로 다운로드한다.
	 * @param
	 * @return
	 */ 
	scwin.btnDownExcel_onclick = function() {
		var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
		var subTitleNm = spnSubTitle.getValue();
		// 엑셀 내부 타이틀 추가_240108
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 6,
			text 		: `${menuNm}_` + `${subTitleNm}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdScrinList, {
			fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			startRowIndex : 1,
			startColumnIndex : 0,
			useDataFormat: true,
			applyDataFormat : true
		}, infoArr);
	};

	/**
	 * 특정 셀을 선택시 해당 내용을 상세내역으로 표출한다.
	 * @param <Int> row
	 * @param <Int> col
	 * @return
	 */
	scwin.grdScrinList_oncellclick = function(row, col) {
		var rowIndex = row;
		var colIndex = col;
		var setJsonData = dltScrinList.getRowJSON(rowIndex);

		scwin.rowIndex = rowIndex;

		// 폼 초기화
		$p.$("#spnFileName").text("");
		$p.$("#trFileName").hide();

		dmaSaveScrin.setJSON(setJsonData);
		dmaSaveScrin.set("lastInfo", dltScrinList.getCellData(rowIndex, "lastUpdtDt") + " " + dltScrinList.getCellData(rowIndex, "lastUpdusrNm"));

		var info = dmaSaveScrin.get("lastInfo");
		// PK 수정 불가능 하도록 수정(초기에는 활성화, 값이 있으면 비활성화)
		if (info != "") {
			ibxScrinId.setDisabled(true);
		}
		// 수정 flag 설정
		dmaSaveScrin.set("rowStatus", "U");
	};

	/**
 	 * 화면ID 등록의 편리함 제공
	 * @param <Object> info
	 * @return
	 */
	scwin.actIntnSysdivCd2_onviewchange = function(info) {
		var oldValue = info.oldValue;
		var newValue = info.newValue;

		if (newValue != "") {
			dmaSaveScrin.set("scrinId", newValue);
			ibxScrinId.focus();
		} else {
			// {0} 은 필수 입력값입니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00004", "시스템구분"));
			dmaSaveScrin.set("scrinId", "");
			actIntnSysdivCd2.focus();
		}
	};

	/**
	 * 입력된 영문자를 대문자로 변환
	 * @param
	 * @return
	 */
	scwin.ibxScrinId_onviewchange = function(info) {
		var newValue = info.newValue;

		if (newValue != "") {
			dmaSaveScrin.set("scrinId" , newValue.toUpperCase());
		}
	};

	/**
	 * 규정정보 돋보기 클릭
	 */
	scwin.btnLinkinfo_onclick = function() {
		if(dmaSaveScrin.get("scrinId") == "") {
			comLib.alert($p, "선택된 화면ID가 없습니다.");
			return false;
		} else {
			var law_url = comLib.LAW_POP_URL.substring(0, comLib.LAW_POP_URL.indexOf("wq")) ;
			var url = law_url + "syslink.jsp?systemid=" + dmaSaveScrin.get("scrinId") + "&ugbn=admin";

			var options = {
				title : "관련 규정.법령 연계",
				width : 900,
				height : 370,
				modal : true,
				closeAction : scwin.regltnLinkUrlCallBack
			};
			comLib.openPopup($p, "SCMSC30000003", url, options);
		}
	};

	/**
	 * 규정정보 돋보기 팝업 callback
	 */
	scwin.regltnLinkUrlCallBack = function() {
		scwin.btnInqire_onclick();

		var url = "syslink.jsp?systemid=" + dmaSaveScrin.get("scrinId");
		dmaSaveScrin.set("linkinfo", url);

		return true;
	};
